1	/**
2	 * 探查：客户列表完整分页 + 对话历史滚动 + 图片URL
3	 */
4	const { chromium } = require('playwright');
5	
6	(async () => {
7	  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
8	  const ctx = browser.contexts()[0];
9	  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
10	  if (!page) { console.log('no page'); return; }
11	
12	  // 已经在客户页面了，检查分页结构
13	  console.log('=== 客户列表分页结构 ===');
14	  const pageInfo = await page.evaluate(() => {
15	    // 分页控件
16	    const pagination = document.querySelector('.okki-pagination, [class*="pagination"]');
17	    if (!pagination) return 'no pagination found';
18	    return {
19	      html: pagination.innerHTML.replace(/</g, '&lt;').substring(0, 2000),
20	      text: pagination.textContent?.trim().substring(0, 200),
21	    };
22	  });
23	  console.log(JSON.stringify(pageInfo, null, 2));
24	
25	  // 检查客户列表行结构
26	  const rowInfo = await page.evaluate(() => {
27	    const rows = document.querySelectorAll('table tr, [class*="row"], [class*="list-item"], .okki-table-row');
28	    return Array.from(rows).slice(0, 5).map((row, i) => ({
29	      idx: i,
30	      text: (row.textContent || '').trim().substring(0, 200),
31	      class: typeof row.className === 'string' ? row.className.substring(0, 80) : '',
32	      html: row.innerHTML.replace(/</g, '&lt;').substring(0, 500),
33	      cells: Array.from(row.querySelectorAll('td, th, [class*="cell"]')).map(c => ({
34	        text: (c.textContent || '').trim().substring(0, 60),
35	        class: (typeof c.className === 'string' ? c.className : '').substring(0, 40),
36	      })),
37	    }));
38	  });
39	  console.log('\n=== 表格行结构 ===');
40	  rowInfo.forEach(r => {
41	    console.log(`\nRow ${r.idx}: class=${r.class}`);
42	    r.cells.forEach((c, i) => console.log(`  Cell ${i}: "${c.text}" (${c.class})`));
43	  });
44	
45	  // 尝试点击第2页
46	  console.log('\n=== 分页导航测试 ===');
47	  const testPage = await page.evaluate(() => {
48	    // 找页码按钮
49	    const links = document.querySelectorAll('.okki-pagination li, .okki-pagination a, .okki-pagination button, [class*="pagination"] a, a[class*="page"]');
50	    for (const el of links) {
51	      if (el.textContent?.trim() === '2') {
52	        el.click();
53	        return `clicked page 2: ${el.outerHTML?.substring(0, 200)}`;
54	      }
55	    }
56	    // Alternative: find the page input or next button
57	    return 'page 2 not found';
58	  });
59	  console.log(testPage);
60	  await new Promise(r => setTimeout(r, 2000));
61	
62	  // 检查URL是否变了
63	  console.log('当前URL:', page.url().substring(0, 300));
64	
65	  // 回到TM页面，检查消息区的"加载更多"按钮
66	  console.log('\n=== TM消息区加载更多 ===');
67	  // 先回到TM页面
68	  await page.evaluate(() => {
69	    const items = document.querySelectorAll('.fixed-menu-item, a');
70	    for (const el of items) {
71	      if (el.textContent?.trim() === '沟通') {
72	        el.click();
73	        return;
74	      }
75	    }
76	  });
77	  await new Promise(r => setTimeout(r, 3000));
78	
79	  const talkFrame = page.frames()[1];
80	  if (!talkFrame) { console.log('no talk frame'); return; }
81	
82	  // 检查消息区顶部是否有加载更多按钮
83	  const loadMore = await talkFrame.evaluate(() => {
84	    // 滚动消息区到顶
85	    const msgFlow = document.querySelector('.message-flow-container.messenger');
86	    if (msgFlow) msgFlow.scrollTop = 0;
87	    // 等待是否有加载触发
88	    return new Promise(resolve => {
89	      setTimeout(() => {
90	        // Check for load more indicators
91	        const loadMoreBtns = document.querySelectorAll('button, a, [class*="load"], [class*="more"], [class*="history"]');
92	        const found = [];
93	        loadMoreBtns.forEach(b => {
94	          const text = b.textContent?.trim() || '';
95	          if (text.toLowerCase().includes('load') || text.toLowerCase().includes('more') || text.includes('历史') || text.includes('加载') || text.includes('更多')) {
96	            found.push(text);
97	          }
98	        });
99	        // Check number of messages again
100	        const msgCount = document.querySelectorAll('.message-item-wrapper.messenger').length;
101	        resolve({ found, msgCount });
102	      }, 3000);
103	    });
104	  });
105	  console.log('加载更多按钮:', JSON.stringify(loadMore));
106	
107	  // 检查消息区是否可无限滚动
108	  const scrollTest = await talkFrame.evaluate(() => {
109	    const msgFlow = document.querySelector('.message-flow-container.messenger');
110	    if (!msgFlow) return { error: 'no message flow' };
111	    const before = msgFlow.scrollHeight;
112	    // Scroll to very top
113	    msgFlow.scrollTop = -100; // Try negative to force trigger
114	    return new Promise(resolve => {
115	      setTimeout(() => {
116	        const after = msgFlow.scrollHeight;
117	        resolve({ before, after, diff: after - before, scrollTop: msgFlow.scrollTop });
118	      }, 3000);
119	    });
120	  });
121	  console.log('消息区滚动测试:', JSON.stringify(scrollTest));
122	
123	  // 获取可点击的图片查看其完整src
124	  const imageUrls = await talkFrame.evaluate(() => {
125	    const urls = new Set();
126	    document.querySelectorAll('.message-item-wrapper.messenger img').forEach(img => {
127	      if (img.src) urls.add(img.src.substring(0, 200));
128	    });
129	    return Array.from(urls).slice(0, 10);
130	  });
131	  console.log('\n图片URL样例:');
132	  imageUrls.forEach((url, i) => console.log(`  [${i}] ${url}`));
133	
134	  await browser.close();
135	})().catch(err => { console.error(err.message); });
136	

