1	/**
2	 * 探查：小满邮件模块 — 邮件和附件
3	 */
4	const { chromium } = require('playwright');
5	
6	(async () => {
7	  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
8	  const ctx = browser.contexts()[0];
9	  let page = ctx.pages().find(p => p.url().includes('xiaoman'));
10	
11	  // 点击"邮件"导航
12	  await page.evaluate(() => {
13	    const items = document.querySelectorAll('.fixed-menu-item, a, li');
14	    for (const el of items) {
15	      if (el.textContent?.trim() === '邮件') {
16	        el.click();
17	        return;
18	      }
19	    }
20	  });
21	  await new Promise(r => setTimeout(r, 4000));
22	
23	  console.log('=== 邮件模块URL ===');
24	  console.log(page.url().substring(0, 300));
25	
26	  // 看页面内容
27	  const content = await page.evaluate(() => {
28	    return document.body?.innerText?.substring(0, 3000) || 'no content';
29	  });
30	  console.log('\n=== 邮件页面内容 ===');
31	  console.log(content);
32	
33	  // 检查frames
34	  const frames = page.frames();
35	  console.log(`\n=== Frames: ${frames.length} ===`);
36	  frames.forEach((f, i) => console.log(`[${i}] ${f.url().substring(0, 200)}`));
37	
38	  // 如果有邮件列表，检查结构
39	  const mailStructure = await page.evaluate(() => {
40	    // Look for mail list
41	    const items = [];
42	    // Try different selectors
43	    document.querySelectorAll('[class*="mail"], [class*="email"], [class*="inbox"], [class*="letter"], table tr, [class*="list-item"], [class*="message-item"], [class*="thread"]').forEach(el => {
44	      const text = (el.textContent || '').trim().substring(0, 100);
45	      const cls = typeof el.className === 'string' ? el.className.substring(0, 60) : '';
46	      if (text && el.getBoundingClientRect().width > 100) {
47	        items.push({ tag: el.tagName, class: cls, text });
48	      }
49	    });
50	    return items.slice(0, 30);
51	  });
52	  console.log('\n=== 邮件列表元素 ===');
53	  mailStructure.forEach((m, i) => console.log(`[${i}] <${m.tag}> ${m.class} "${m.text}"`));
54	
55	  // 查找附件链接/按钮
56	  const hasAttachments = await page.evaluate(() => {
57	    return {
58	      attachLinks: document.querySelectorAll('a[href*="attach"], a[href*="file"], [class*="attach"], [class*="file"], i[class*="attach"]').length,
59	      downloadLinks: document.querySelectorAll('a[href*="download"], [class*="download"]').length,
60	      imgCount: document.querySelectorAll('img[src*="alicdn"], img[src*="aliyun"]').length,
61	    };
62	  });
63	  console.log('\n=== 附件统计 ===');
64	  console.log(JSON.stringify(hasAttachments));
65	
66	  await browser.close();
67	})().catch(err => { console.error(err.message); });
68	

