1	/**
2	 * 探查：TM聊天中的文件和附件类型
3	 */
4	const { chromium } = require('playwright');
5	
6	(async () => {
7	  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
8	  const ctx = browser.contexts()[0];
9	  let page = ctx.pages().find(p => p.url().includes('xiaoman'));
10	
11	  // 确保在沟通/TM页面
12	  if (!page.url().includes('talk')) {
13	    await page.evaluate(() => {
14	      const items = document.querySelectorAll('.fixed-menu-item, a');
15	      for (const el of items) {
16	        if (el.textContent?.trim() === '沟通') { el.click(); return; }
17	      }
18	    });
19	    await new Promise(r => setTimeout(r, 4000));
20	    // Re-acquire page reference
21	    page = ctx.pages().find(p => p.url().includes('xiaoman'));
22	  }
23	
24	  const tf = page.frames()[1];
25	  if (!tf) { console.log('no talk frame'); return; }
26	
27	  // 点击第一个有真实消息的会话
28	  await tf.evaluate(() => {
29	    const containers = document.querySelectorAll('.contact-item-container');
30	    for (const c of containers) {
31	      const text = c.textContent || '';
32	      if (!text.includes('Assistant') && !text.includes('自动接待') && !text.includes('Eva')) {
33	        c.click();
34	        return;
35	      }
36	    }
37	  });
38	  await new Promise(r => setTimeout(r, 2500));
39	
40	  // 分析消息结构
41	  const structure = await tf.evaluate(() => {
42	    const msgTypes = {};
43	    document.querySelectorAll('.message-item-wrapper.messenger').forEach(w => {
44	      // Top-level class
45	      const topCls = typeof w.className === 'string' ? w.className : '';
46	      msgTypes[topCls] = (msgTypes[topCls] || 0) + 1;
47	
48	      // Direct children class names
49	      w.querySelectorAll(':scope > *').forEach(c => {
50	        const cls = typeof c.className === 'string' ? c.className : '';
51	        const key = `CHILD: ${cls.substring(0, 80)}`;
52	        msgTypes[key] = (msgTypes[key] || 0) + 1;
53	
54	        // Check for special elements
55	        c.querySelectorAll('img, a, video, audio, iframe, embed, object').forEach(el => {
56	          const tag = el.tagName.toLowerCase();
57	          const extras = [];
58	          if (el.src) extras.push(`src=${el.src.substring(0, 80)}`);
59	          if (el.href) extras.push(`href=${el.href.substring(0, 80)}`);
60	          const key2 = `${tag}: ${extras.join(' ')}`;
61	          msgTypes[key2] = (msgTypes[key2] || 0) + 1;
62	        });
63	      });
64	    });
65	    return msgTypes;
66	  });
67	
68	  console.log('=== 消息结构和文件类型 ===');
69	  Object.entries(structure).sort((a, b) => b[1] - a[1]).forEach(([k, v]) => {
70	    console.log(`  ${v}x ${k.substring(0, 150)}`);
71	  });
72	
73	  // 检查云盘文件
74	  const cloudFiles = await tf.evaluate(() => {
75	    const items = [];
76	    document.querySelectorAll('a[href*="clouddisk"], a[href*="file"], a[href*="download"], a[href*="aliyun"], [class*="file"], [class*="attach"], [class*="down"]').forEach(el => {
77	      items.push({
78	        text: (el.textContent || '').trim().substring(0, 60),
79	        href: (el.href || '').substring(0, 150),
80	        class: (typeof el.className === 'string' ? el.className : '').substring(0, 50),
81	      });
82	    });
83	    return items;
84	  });
85	  console.log(`\n=== 云盘/文件链接: ${cloudFiles.length} 个 ===`);
86	  cloudFiles.forEach(f => console.log(`  "${f.text}" ${f.href} [${f.class}]`));
87	
88	  await browser.close();
89	})().catch(err => { console.error(err.message); });
90	

