1	/**
2	 * 探查：客户全量列表 + 会话消息滚动 + 图片处理
3	 */
4	const { chromium } = require('playwright');
5	
6	(async () => {
7	  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
8	  const ctx = browser.contexts()[0];
9	  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
10	  if (!page) { console.log('no page'); return; }
11	
12	  console.log('=== 当前URL ===');
13	  console.log(page.url());
14	
15	  // 1. TM聊天 — 滚动加载更多会话，看能加载多少
16	  const talkFrame = page.frames()[1];
17	  if (!talkFrame) { console.log('no talk frame'); return; }
18	
19	  console.log('\n=== TM 会话列表滚动测试 ===');
20	  // 先获取当前可见数
21	  let before = await talkFrame.evaluate(() => document.querySelectorAll('.contact-item-container').length);
22	  console.log(`滚动前: ${before} 个会话`);
23	
24	  // 多次滚动到底部
25	  for (let i = 0; i < 10; i++) {
26	    await talkFrame.evaluate(() => {
27	      const c = document.querySelector('.seller-conversation-list') || document.querySelector('.conversation-list-content');
28	      if (c) c.scrollTop = c.scrollHeight;
29	    });
30	    await new Promise(r => setTimeout(r, 800));
31	    const after = await talkFrame.evaluate(() => document.querySelectorAll('.contact-item-container').length);
32	    if (after === before) break; // no more loaded
33	    console.log(`滚动 ${i + 1}: ${before} → ${after}`);
34	    before = after;
35	  }
36	  console.log(`最终: ${before} 个会话`);
37	
38	  // 2. 检查一个消息区能滚动加载多少历史消息
39	  console.log('\n=== 消息历史滚动测试 ===');
40	  // 点击第一个会话
41	  await talkFrame.evaluate(() => {
42	    const first = document.querySelector('.contact-item-container');
43	    if (first) first.click();
44	  });
45	  await new Promise(r => setTimeout(r, 2000));
46	
47	  // 先看当前可见消息数
48	  let msgBefore = await talkFrame.evaluate(() => document.querySelectorAll('.message-item-wrapper.messenger').length);
49	  console.log(`滚动消息前: ${msgBefore} 条可见`);
50	
51	  // 滚动消息区顶部加载历史
52	  for (let i = 0; i < 8; i++) {
53	    await talkFrame.evaluate(() => {
54	      const c = document.querySelector('.message-flow-container.messenger');
55	      if (c) c.scrollTop = 0; // scroll to top to trigger history loading
56	    });
57	    await new Promise(r => setTimeout(r, 1500));
58	    const msgAfter = await talkFrame.evaluate(() => document.querySelectorAll('.message-item-wrapper.messenger').length);
59	    if (msgAfter === msgBefore) break;
60	    console.log(`消息滚动 ${i + 1}: ${msgBefore} → ${msgAfter}`);
61	    msgBefore = msgAfter;
62	  }
63	  console.log(`最终消息: ${msgBefore} 条`);
64	
65	  // 3. 检查图片消息在DOM中的样子
66	  console.log('\n=== 图片消息检测 ===');
67	  const imgInfo = await talkFrame.evaluate(() => {
68	    const items = [];
69	    // Look for image-related elements in messages
70	    document.querySelectorAll('.message-item-wrapper.messenger').forEach(el => {
71	      const imgs = el.querySelectorAll('img, [class*="image"], [class*="img"], [class*="picture"], [style*="background-image"]');
72	      const text = el.textContent?.substring(0, 80) || '';
73	      if (imgs.length > 0 || text.includes('[图片]') || text.includes('[image]')) {
74	        items.push({
75	          text: text.substring(0, 60),
76	          imgCount: imgs.length,
77	          imgTags: Array.from(imgs).map(i => i.tagName + (i.src ? ` src=${i.src.substring(0, 80)}` : '')),
78	        });
79	      }
80	    });
81	    return items.slice(0, 10);
82	  });
83	  console.log(`找到 ${imgInfo.length} 条含图片的消息`);
84	  imgInfo.forEach((item, i) => {
85	    console.log(`  [${i}] "${item.text}" 图片: ${item.imgCount} 个`);
86	    item.imgTags.forEach(t => console.log(`    ${t}`));
87	  });
88	
89	  // 4. 尝试切换到"客户"模块
90	  console.log('\n=== 客户模块探查 ===');
91	  // Click the 客户 menu item in sidebar
92	  const custNav = await page.evaluate(() => {
93	    const items = document.querySelectorAll('.fixed-menu-item, a, li');
94	    for (const el of items) {
95	      if (el.textContent?.trim() === '客户') {
96	        el.click();
97	        return 'clicked 客户';
98	      }
99	    }
100	    return 'not found';
101	  });
102	  console.log(custNav);
103	  await new Promise(r => setTimeout(r, 3000));
104	  console.log('跳转后URL:', page.url());
105	
106	  // Check if page content changed
107	  const pageText = await page.evaluate(() => document.body?.innerText?.substring(0, 3000) || '');
108	  console.log('页面内容:\n', pageText);
109	
110	  await browser.close();
111	})().catch(err => { console.error(err.message); });
112	

