59	  if (urls.length === 0) return [];
60	
61	  const dir = join(IMAGES_DIR, sanitizeName(customerName));
62	  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
63	
64	  const saved = [];
65	  for (const url of urls) {
66	    if (globalDedup.has(url)) continue;
67	    globalDedup.add(url);
68	
69	    const ext = url.match(/\.(jpe?g|png|gif|webp|bmp)(?:[?#]|$)/i)?.[1] || 'jpg';
70	    const hash = createHash('md5').update(url).digest('hex').substring(0, 10);
71	    const filename = `${Date.now()}_${hash}.${ext}`;
72	    const filePath = join(dir, filename);
73	
74	    try {
75	      const size = await downloadImageViaContext(ctx, url, filePath);
76	      saved.push({ url, filePath, size });
77	    } catch (err) {
78	      // Silent skip — some images may be expired or restricted
79	      console.log(`   ⚠️ 图片跳过: ${url.substring(0, 60)}… (${err.message})`);
80	    }
81	  }
82	  return saved;
83	}
