88	export function extractMessageImages(frame) {
89	  return frame.evaluate(() => {
90	    const results = [];
91	    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
92	      const imgs = wrapper.querySelectorAll('img');
93	      if (imgs.length === 0) return;
94	      const urls = Array.from(imgs)
95	        .map(img => img.src)
96	        .filter(s => s && s.startsWith('http'));
97	      if (urls.length > 0) results.push(...urls);
98	    });
99	    return [...new Set(results)];
100	  });
101	}
