103	/**
104	 * 提取当前会话消息中的文件链接（云盘/下载等）
105	 */
106	export async function extractFileUrls(frame) {
107	  return frame.evaluate(() => {
108	    const files = [];
109	    document.querySelectorAll('.message-item-wrapper.messenger').forEach(wrapper => {
110	      // 卡消息中的链接
111	      wrapper.querySelectorAll('a').forEach(a => {
112	        const href = a.href || '';
113	        if (href.includes('clouddisk') || href.includes('download') || href.includes('aliyundoc')) {
114	          files.push({
115	            url: href,
116	            name: (a.textContent || '').trim() || (a.title || ''),
117	            type: 'clouddisk',
118	          });
119	        }
120	      });
121	      // 文件类元素的文本内容
122	      const cardText = wrapper.querySelector('.session-rich-content.card');
123	      if (cardText) {
124	        const text = cardText.textContent || '';
125	        // 常见的文件格式指示
126	        if (/\.(pdf|docx?|xlsx?|pptx?|zip|rar|jpg|png)\b/i.test(text) && !files.some(f => f.text === text)) {
127	          files.push({ url: '', name: text.substring(0, 100), type: 'card_reference' });
128	        }
129	      }
130	    });
131	    return files;
132	  });
133	}
