10	
11	// ============================================================
12	// 分类定义
13	// ============================================================
14	
15	export const CATEGORIES = [
16	  { id: 'awaiting_reply',    label: '待回复',   emoji: '🔴', priority: 'P0', desc: '客户发来消息，我方未回复' },
17	  { id: 'awaiting_quote',    label: '待报价',   emoji: '🟠', priority: 'P0', desc: '客户询盘，未正式报价' },
18	  { id: 'negotiating',       label: '谈判中',   emoji: '💬', priority: 'P0', desc: '正讨论价格/条款/细节' },
19	  { id: 'after_sales',       label: '售后处理', emoji: '⚠️', priority: 'P0', desc: '质量投诉、退换货' },
20	  { id: 'sample_request',    label: '待寄样',   emoji: '📦', priority: 'P1', desc: '客户要求样品' },
21	  { id: 'sample_followup',   label: '样品跟进', emoji: '🔬', priority: 'P1', desc: '样品已寄出，等反馈' },
22	  { id: 'awaiting_payment',  label: '待付款',   emoji: '🟡', priority: 'P1', desc: 'PI已发，等付款' },
23	  { id: 'awaiting_delivery', label: '待发货',   emoji: '🟢', priority: 'P1', desc: '已收款，未发货' },
24	  { id: 'followup',          label: '待回访',   emoji: '🔵', priority: 'P2', desc: '历史有交互，超N天未联系' },
25	  { id: 'keep_warm',         label: '保持粘性', emoji: '🟣', priority: 'P3', desc: '老客户/长期客户维系' },
26	  { id: 'activate',          label: '待激活',   emoji: '⚪', priority: 'P3', desc: '新线索/低互动客户' },
27	];
28	
29	// ============================================================
30	// 关键词定义
31	// ============================================================
32	
33	const KEYWORDS = {
34	  // 价格/报价相关
35	  price: ['price', 'quote', 'quotation', 'cost', 'how much', '收费', '价格', '报价', 'money', 'dollar', 'usd', 'pi', 'proforma', 'invoice'],
36	  // 样品相关
37	  sample: ['sample', '样品', '试样', 'test order', 'try', 'trial', 'small order', 'sample fee'],
38	  // 付款相关
39	  payment: ['payment', 'pay', 'deposit', '定金', '预付', '付款', 'tt', 'wire transfer', 'bank', '账期'],
40	  // 售后相关
41	  after_sales: ['complaint', 'return', 'refund', '退换', '退款', '投诉', 'quality', 'damage', 'wrong', 'defect', '破损', 'quality issue', 'not as described'],
42	  // 物流相关
43	  shipping: ['ship', 'delivery', 'logistics', '海运', '空运', '快递', 'dhl', 'fedex', 'ups', '海运', 'shipping cost', 'freight'],
44	  // 谈判相关
45	  negotiation: ['negotiate', 'discount', 'better price', 'cheaper', '最低', '优惠', '折扣', 'moq', 'minimum', '交期', 'lead time'],
46	  // 合作意向
47	  interest: ['interested', '合作', 'order', 'purchase', 'buy', '采购', '下单', 'confirm', '确认订单', 'catalog', 'product list'],
48	  // 客户信息询问
49	  inquiry: ['what is', 'tell me', 'do you have', '可以提供', '能做', '定制', 'custom', 'odm', 'oem', 'printing'],
50	  // 跟进问候
51	  followup_greeting: ['how are you', 'checking in', 'following up', 'just follow', 'any thought', 'any update', 'how is everything'],
52	};
53	
54	// ============================================================
55	// 辅助函数
56	// ============================================================
57	
58	function lastMessage(messages) {
59	  return messages.length > 0 ? messages[messages.length - 1] : null;
60	}
61	
62	function firstMessage(messages) {
63	  return messages.length > 0 ? messages[0] : null;
64	}
65	
66	function hasKeywords(text, keywordList) {
67	  if (!text) return false;
68	  const lower = text.toLowerCase();
69	  return keywordList.some(kw => lower.includes(kw.toLowerCase()));
70	}
71	
72	function extractSentMessages(messages) {
73	  return messages.filter(m => m.side === 'sent');
74	}
75	
76	function extractReceivedMessages(messages) {
77	  return messages.filter(m => m.side === 'received');
78	}
79	
80	function countKeywordMatches(text, keywordList) {
81	  if (!text) return 0;
82	  const lower = text.toLowerCase();
83	  return keywordList.filter(kw => lower.includes(kw.toLowerCase())).length;
84	}
85	
86	/**
87	 * 估算消息时间戳（相对当前时间）
88	 */
89	function estimateHoursAgo(messageIndex, totalMessages, avgHoursPerMsg = 4) {
90	  // Rough estimate: each message back and forth is about 4 hours apart
91	  // This is very approximate
92	  return (totalMessages - messageIndex) * avgHoursPerMsg;
93	}
94	
95	// ============================================================
96	// 分类引擎
97	// ============================================================
98	
99	/**
100	 * @param {Object} conv - 会话对象 { name, status, messages: [{ side, content, isCard }] }
101	 * @returns {{ categoryId: string, tier: string, confidence: number, reasons: string[] }}
102	 */
103	export function classifyConversation(conv) {
104	  const { messages = [], status } = conv;
105	  const last = lastMessage(messages);
106	  const first = firstMessage(messages);
107	  const sent = extractSentMessages(messages);
108	  const received = extractReceivedMessages(messages);
109	  const reasons = [];
110	
111	  if (messages.length === 0) {
112	    return { categoryId: 'activate', tier: 'C', confidence: 0.5, reasons: ['无消息记录'] };
113	  }
114	
115	  const lastContent = last ? last.content.toLowerCase() : '';
116	  const allContent = messages.map(m => m.content).join(' ').toLowerCase();
117	  const sentContent = sent.map(m => m.content).join(' ').toLowerCase();
118	  const receivedContent = received.map(m => m.content).join(' ').toLowerCase();
119	
120	  // ===================================================
121	  // 规则引擎（按优先级）
122	  // ===================================================
123	
124	  // 规则 1: 售后处理 — 投诉/退换货关键词
125	  if (hasKeywords(allContent, KEYWORDS.after_sales)) {
126	    const matchCount = countKeywordMatches(allContent, KEYWORDS.after_sales);
127	    if (matchCount >= 1) {
128	      reasons.push(`含售后关键词(${matchCount}次)`);
129	      const tier = matchCount >= 3 ? 'S' : 'A';
130	      return { categoryId: 'after_sales', tier, confidence: 0.8, reasons };
131	    }
132	  }
133	
134	  // 规则 2: 待回复 — 最后一条消息是客户发的，我方未回复
135	  if (last && last.side === 'received') {
136	    const lastSent = sent.length > 0 ? sent[sent.length - 1] : null;
137	    const lastReceived = received[received.length - 1];
138	    if (!lastSent || messages.indexOf(lastReceived) > messages.indexOf(lastSent)) {
139	      reasons.push('客户最后发言，我方未回复');
140	      // Check if it's a price inquiry or just a simple message
141	      const isQuoteRequest = hasKeywords(lastContent, KEYWORDS.price) || hasKeywords(lastContent, KEYWORDS.inquiry);
142	      const isSimpleReply = lastContent.length < 30 && !hasKeywords(lastContent, [...KEYWORDS.price, ...KEYWORDS.interest]);
143	
144	      if (isQuoteRequest) {
145	        reasons.push('包含询价/询盘内容');
146	        return { categoryId: 'awaiting_quote', tier: 'A', confidence: 0.85, reasons };
147	      }
148	      if (hasKeywords(lastContent, KEYWORDS.payment)) {
149	        reasons.push('客户询问付款');
150	        return { categoryId: 'awaiting_payment', tier: 'S', confidence: 0.8, reasons };
151	      }
152	      if (hasKeywords(lastContent, KEYWORDS.sample)) {
153	        reasons.push('客户提及样品');
154	        return { categoryId: 'sample_request', tier: 'A', confidence: 0.75, reasons };
155	      }
156	      if (isSimpleReply) {
157	        reasons.push('简短回复，可能是确认或跟进');
158	        // Is this after we sent a quote/PI?
159	        const recentSentContent = sent.slice(-3).map(m => m.content).join(' ').toLowerCase();
160	        if (hasKeywords(recentSentContent, [...KEYWORDS.price, ...KEYWORDS.payment])) {
161	          reasons.push('我方最近发送过报价');
162	          return { categoryId: 'awaiting_reply', tier: 'A', confidence: 0.75, reasons };
163	        }
164	      }
165	      return { categoryId: 'awaiting_reply', tier: 'B', confidence: 0.7, reasons };
166	    }
167	  }
168	
169	  // 规则 3: 谈判中 — 双方有互动，讨论价格/条款
170	  if (sent.length >= 2 && received.length >= 2) {
171	    const hasPrice = hasKeywords(allContent, KEYWORDS.price);
172	    const hasNegotiation = hasKeywords(allContent, KEYWORDS.negotiation);
173	    if (hasPrice || hasNegotiation) {
174	      reasons.push('双方多轮互动');
175	      if (hasPrice) reasons.push('讨论价格');
176	      if (hasNegotiation) reasons.push('涉及谈判');
177	      const tier = hasPrice && hasNegotiation ? 'S' : (hasPrice ? 'A' : 'B');
178	      return { categoryId: 'negotiating', tier, confidence: 0.8, reasons };
179	    }
180	  }
181	
182	  // 规则 4: 待付款 — 我方发送了报价/PI，等待客户付款
183	  if (hasKeywords(sentContent, KEYWORDS.payment) || hasKeywords(sentContent, KEYWORDS.price)) {
184	    // Last message was from us about payment/price, customer hasn't responded or responded briefly
185	    if (last && last.side === 'sent') {
186	      const hasPaymentKeywords = hasKeywords(lastContent, KEYWORDS.payment) || hasKeywords(sentContent, KEYWORDS.payment);
187	      if (hasPaymentKeywords) {
188	        reasons.push('我方发送了付款相关信息');
189	        return { categoryId: 'awaiting_payment', tier: 'A', confidence: 0.7, reasons };
190	      }
191	      if (hasKeywords(sentContent, KEYWORDS.price)) {
192	        reasons.push('我方已发送报价');
193	        // Check if customer replied
194	        const recentCustomerMessages = received.slice(-2);
195	        const hasCustomerInterest = recentCustomerMessages.some(m =>
196	          hasKeywords(m.content, [...KEYWORDS.interest, ...KEYWORDS.negotiation])
197	        );
198	        if (hasCustomerInterest) {
199	          return { categoryId: 'negotiating', tier: 'A', confidence: 0.75, reasons };
200	        }
201	        return { categoryId: 'awaiting_quote', tier: 'B', confidence: 0.65, reasons };
202	      }
203	    }
204	  }
205	
206	  // 规则 5: 样品相关
207	  if (hasKeywords(allContent, KEYWORDS.sample)) {
208	    reasons.push('涉及样品讨论');
209	    if (last && last.side === 'received') {
210	      // Customer's last message was about samples
211	      return { categoryId: 'sample_followup', tier: 'A', confidence: 0.7, reasons };
212	    }
213	    // We last spoke about samples
214	    const sampleSent = sent.some(m => hasKeywords(m.content, KEYWORDS.sample));
215	    if (sampleSent && last && last.side === 'sent') {
216	      return { categoryId: 'sample_followup', tier: 'B', confidence: 0.65, reasons };
217	    }
218	    return { categoryId: 'sample_request', tier: 'B', confidence: 0.6, reasons };
219	  }
220	
221	  // 规则 6: 消息量判断
222	  const totalMsgCount = messages.length;
223	
224	  // 只有1-2条消息 = 新线索/待激活
225	  if (totalMsgCount <= 2) {
226	    reasons.push(`仅有${totalMsgCount}条消息`);
227	    return { categoryId: 'activate', tier: 'C', confidence: 0.7, reasons };
228	  }
229	
230	  // 3-5条消息 = 可能是潜在客户待跟进
231	  if (totalMsgCount <= 5) {
232	    if (last && last.side === 'sent') {
233	      reasons.push('少量互动，我方最后发言');
234	      return { categoryId: 'followup', tier: 'B', confidence: 0.6, reasons };
235	    }
236	    reasons.push('少量互动');
237	    return { categoryId: 'activate', tier: 'C', confidence: 0.55, reasons };
238	  }
239	
240	  // 规则 7: 我方最后发言但客户未回复 → 待回访
241	  if (last && last.side === 'sent') {
242	    reasons.push('我方最后发言');
243	    const recentContent = messages.slice(-3).map(m => m.content).join(' ').toLowerCase();
244	
245	    if (hasKeywords(recentContent, [...KEYWORDS.followup_greeting, ...KEYWORDS.inquiry])) {
246	      reasons.push('含跟进/问候内容');
247	      return { categoryId: 'followup', tier: 'B', confidence: 0.7, reasons };
248	    }
249	    return { categoryId: 'followup', tier: 'C', confidence: 0.55, reasons };
250	  }
251	
252	  // 规则 8: 默认
253	  if (totalMsgCount > 10) {
254	    reasons.push('历史互动较多');
255	    return { categoryId: 'keep_warm', tier: 'C', confidence: 0.4, reasons };
256	  }
257	
258	  return { categoryId: 'activate', tier: 'C', confidence: 0.3, reasons };
259	}
260	
261	/**
262	 * 批量分类
263	 */
264	export function classifyAll(conversations) {
265	  return conversations.map(conv => ({
266	    ...conv,
267	    classification: classifyConversation(conv),
268	  }));
269	}
270	
271	/**
272	 * 获取分类详情
273	 */
274	export function getCategoryInfo(categoryId) {
275	  return CATEGORIES.find(c => c.id === categoryId);
276	}
277	
278	/**
279	 * 按分类统计
280	 */
281	export function categorizeSummary(classifiedConversations) {
282	  const summary = {};
283	  for (const cat of CATEGORIES) {
284	    summary[cat.id] = { ...cat, conversations: [], count: 0 };
285	  }
286	
287	  // 未匹配的归入其他
288	  summary.other = { id: 'other', label: '其他', emoji: '❓', priority: 'P4', conversations: [], count: 0 };
289	
290	  for (const conv of classifiedConversations) {
291	    const catId = conv.classification?.categoryId || 'other';
292	    if (summary[catId]) {
293	      summary[catId].conversations.push(conv);
294	      summary[catId].count++;
295	    } else {
296	      summary.other.conversations.push(conv);
297	      summary.other.count++;
298	    }
299	  }
300	
301	  // 按优先级排序
302	  const priority = { 'P0': 0, 'P1': 1, 'P2': 2, 'P3': 3, 'P4': 4 };
303	  return Object.values(summary)
304	    .filter(c => c.count > 0)
305	    .sort((a, b) => (priority[a.priority] || 99) - (priority[b.priority] || 99));
306	}
