49	function loadLatest(pattern) {
50	  const files = readdirSync(DATA_DIR)
51	    .filter(f => f.startsWith(pattern) && f.endsWith('.json'))
52	    .sort().reverse();
53	  if (!files.length) return [];
54	  return JSON.parse(readFileSync(join(DATA_DIR, files[0]), 'utf-8'));
55	}
56	
57	// ============================================================
58	// 匹配客户名
59	// ============================================================
60	function matchCustomer(text, names) {
61	  if (!text) return null;
62	  const lower = text.toLowerCase();
63	  for (const name of names) {
64	    if (!name || name === 'User name') continue;
65	    if (lower.includes(name.toLowerCase())) return name;
66	    const parts = name.toLowerCase().split(/\s+/).filter(Boolean);
67	    for (const part of parts) {
68	      if (part.length > 2 && lower.includes(part)) return name;
69	    }
70	  }
71	  return null;
72	}
