322	function mkCell(text, runOpts = {}, shadeColor, width) {
323	  const runs = typeof text === 'string'
324	    ? [new TextRun({ text, ...runOpts })]
325	    : text;
326	
327	  const shading = shadeColor ? { fill: shadeColor, type: ShadingType.CLEAR } : undefined;
328	
329	  return new TableCell({
330	    children: [new Paragraph({ children: runs, alignment: runOpts.align || AlignmentType.LEFT })],
331	    width: width ? { size: width, type: WidthType.DXA } : undefined,
332	    shading,
333	    verticalAlign: 'center',
334	  });
335	}
