27	// ============================================================
28	async function connect() {
29	  const browser = await chromium.connectOverCDP(CDP_URL);
30	  const ctx = browser.contexts()[0];
31	  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
32	  if (!page) throw new Error('未找到小满页面');
33	  const talkFrame = page.frames()[1];
34	  if (!talkFrame) throw new Error('未找到聊天 iframe');
35	  return { browser, ctx, page, talkFrame };
36	}
