91	async function clickConversation(frame, index) {
92	  const result = await frame.evaluate((idx) => {
93	    const containers = document.querySelectorAll('.contact-item-container');
94	    const target = containers[idx];
95	    if (!target) return null;
96	    target.scrollIntoView({ block: 'center' });
97	    target.click();
98	    return (target.textContent || '').trim().substring(0, 150);
99	  }, index);
100	  await new Promise(r => setTimeout(r, 2000));
101	  return result;
102	}
